SELECT [DDT_Picking Line].[Document No_], Sum(Val([quantity])) AS QTY, [Sales Header].[Salesperson Code], [DDT_Picking Line].[Sell-to Customer No_]
FROM ([DDT_Picking Line] INNER JOIN [Sales Header] ON [DDT_Picking Line].[Order No_] = [Sales Header].No_) INNER JOIN [DDT_Picking Header] ON [DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_
WHERE ((([DDT_Picking Line].type)=2) AND (([DDT_Picking Line].[Document Type])=0) AND (([DDT_Picking Line].[Model Item No_])="S0QUEENS01/MES") AND (([DDT_Picking Line].[Variable Code 01])="NVY") AND (([DDT_Picking Header].Status)=1)) OR ((([DDT_Picking Line].type)=2) AND (([DDT_Picking Line].[Document Type])=0) AND (([DDT_Picking Line].[Model Item No_])="S0TYLER02/MES") AND (([DDT_Picking Line].[Variable Code 01])="NVY") AND (([DDT_Picking Header].Status)=1)) OR ((([DDT_Picking Line].type)=2) AND (([DDT_Picking Line].[Document Type])=0) AND (([DDT_Picking Line].[Model Item No_])="S0QUEENS01/STO") AND (([DDT_Picking Line].[Variable Code 01])="NVR") AND (([DDT_Picking Header].Status)=1))
GROUP BY [DDT_Picking Line].[Document No_], [Sales Header].[Salesperson Code], [DDT_Picking Line].[Sell-to Customer No_]
HAVING ((([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette] Or ([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette] Or ([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette])) OR ((([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette] Or ([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette] Or ([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette])) OR ((([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette] Or ([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette] Or ([Sales Header].[Salesperson Code])=[Forms]![principale]![FiltroAgenteStampaEtichette]));

